import numpy as np

def outer(a, b):
    a = np.asarray(a, dtype=float).reshape(-1, 1)  # (m, 1)
    b = np.asarray(b, dtype=float).reshape(1, -1)  # (1, n)
    return a * b  # broadcasts to (m, n)


def rank1_approx(A):
    A = np.asarray(A, dtype=float)
    U, S, Vt = np.linalg.svd(A, full_matrices=False)
    # Best rank-1: sigma_1 * u_1 * v_1^T
    return S[0] * np.outer(U[:, 0], Vt[0, :])
